// Extract workflows from n8n API response
const items = $input.all();
const workflows = [];

for (const item of items) {
  const data = item.json.data || item.json || [];
  if (Array.isArray(data)) {
    workflows.push(...data);
  } else if (data.id) {
    workflows.push(data);
  }
}

// Extract integrations from nodes
function extractIntegrations(nodes) {
  const integrations = new Set();
  for (const node of nodes || []) {
    if (node.type && node.type.includes('.')) {
      const service = node.type.split('.')[0];
      if (service && service !== 'n8n-nodes-base') {
        integrations.add(service);
      }
    }
  }
  return Array.from(integrations);
}

// Process each workflow
return workflows.map(workflow => ({
  json: {
    id: workflow.id,
    name: workflow.name,
    active: workflow.active || false,
    nodes: workflow.nodes || [],
    connections: workflow.connections || {},
    settings: workflow.settings || {},
    staticData: workflow.staticData || {},
    tags: workflow.tags || [],
    createdAt: workflow.createdAt,
    updatedAt: workflow.updatedAt,
    description: workflow.description || workflow.name,
    nodeCount: (workflow.nodes || []).length,
    integrations: extractIntegrations(workflow.nodes || [])
  }
}));

// Extract products from Boost.space API response
const items = $input.all();
const products = [];

for (const item of items) {
  const data = Array.isArray(item.json) ? item.json : (item.json.data || []);
  if (Array.isArray(data)) {
    products.push(...data);
  } else if (data.id) {
    products.push(data);
  }
}

// Create map of workflow_id (SKU) to product
const productMap = {};
for (const product of products) {
  const workflowId = product.sku || product.customFieldsValues?.find(
    f => f.customFieldInputName === 'workflow_id'
  )?.value;
  if (workflowId) {
    productMap[workflowId] = product;
  }
}

return Object.values(productMap).map(product => ({
  json: {
    id: product.id,
    sku: product.sku,
    name: product.name,
    workflowId: product.sku || product.customFieldsValues?.find(
      f => f.customFieldInputName === 'workflow_id'
    )?.value,
    updatedAt: product.updatedAt || product.createdAt,
    product: product
  }
}));

// Compare n8n workflows with Boost.space products
// Determine actions: CREATE, UPDATE, DELETE

const allInputs = $input.all();
const n8nWorkflows = allInputs.find(item => item.json.id && item.json.name) ? [allInputs.find(item => item.json.id && item.json.name).json] : allInputs.filter(item => item.json.id && item.json.name).map(item => item.json);
const boostSpaceProducts = allInputs.find(item => item.json.workflowId) ? [allInputs.find(item => item.json.workflowId).json] : allInputs.filter(item => item.json.workflowId).map(item => item.json);

// If we got arrays from previous nodes, flatten them
const workflows = Array.isArray(n8nWorkflows[0]) ? n8nWorkflows[0] : n8nWorkflows;
const products = Array.isArray(boostSpaceProducts[0]) ? boostSpaceProducts[0] : boostSpaceProducts;

// Create maps for quick lookup
const n8nMap = {};
const boostSpaceMap = {};

// Map n8n workflows by ID
for (const workflow of workflows) {
  if (workflow.id) {
    n8nMap[workflow.id] = workflow;
  }
}

// Map Boost.space products by workflow_id (SKU)
for (const product of products) {
  const workflowId = product.workflowId || product.sku;
  if (workflowId) {
    boostSpaceMap[workflowId] = product;
  }
}

const actions = [];

// 1. CREATE: Workflows in n8n but not in Boost.space
for (const workflowId in n8nMap) {
  if (!boostSpaceMap[workflowId]) {
    actions.push({
      action: 'CREATE',
      workflowId: workflowId,
      workflow: n8nMap[workflowId],
      reason: 'New workflow in n8n'
    });
  }
}

// 2. UPDATE: Workflows in both (check if updated)
for (const workflowId in n8nMap) {
  if (boostSpaceMap[workflowId]) {
    const workflow = n8nMap[workflowId];
    const product = boostSpaceMap[workflowId].product;

    // Check if workflow was updated (compare updatedAt)
    const workflowUpdated = new Date(workflow.updatedAt || workflow.createdAt);
    const productUpdated = new Date(product.updatedAt || product.createdAt);

    // Also check if name changed
    const nameChanged = workflow.name !== product.name;

    if (workflowUpdated > productUpdated || nameChanged) {
      actions.push({
        action: 'UPDATE',
        workflowId: workflowId,
        workflow: workflow,
        product: product,
        reason: workflowUpdated > productUpdated ? 'Workflow updated in n8n' : 'Name changed'
      });
    }
  }
}

// 3. DELETE: Products in Boost.space but not in n8n
for (const workflowId in boostSpaceMap) {
  if (!n8nMap[workflowId]) {
    actions.push({
      action: 'DELETE',
      workflowId: workflowId,
      product: boostSpaceMap[workflowId].product,
      reason: 'Workflow deleted from n8n'
    });
  }
}

return actions.map(action => ({ json: action }));

// Map workflow to Boost.space Product format
// Based on populate-all-workflows-to-products.cjs

const workflow = $input.item.json.workflow;

// Determine category
function getCategory(name) {
  const n = name.toUpperCase();
  if (n.startsWith('INT-')) return 'Internal';
  if (n.startsWith('SUB-')) return 'Subscription';
  if (n.startsWith('MKT-')) return 'Marketing';
  if (n.startsWith('DEV-')) return 'Development';
  if (n.startsWith('TEST-')) return 'Development';
  if (n.includes('CUSTOMER') || n.includes('CLIENT')) return 'Customer';
  return 'Internal';
}

// Determine status
function getStatus(workflow) {
  if (!workflow.active) return '❌ Deprecated';
  if (workflow.name.includes('Template') || workflow.name.includes('TEMPLATE')) return '📦 Template';
  return '✅ Active';
}

// Determine marketplace readiness
function getMarketplaceReadiness(workflow, category) {
  if (category === 'Internal') return 'not_applicable';
  if (workflow.name.includes('Template') || workflow.name.includes('TEMPLATE')) {
    return 'ready_for_review';
  }
  return 'not_ready';
}

const category = getCategory(workflow.name);
const status = getStatus(workflow);
const marketplaceReadiness = getMarketplaceReadiness(workflow, category);

// Build product payload (simplified - custom fields would need field IDs)
const product = {
  name: workflow.name,
  description: workflow.description || workflow.name,
  sku: workflow.id,
  spaces: [59]
};

return { json: { product, workflow } };

// Map workflow updates to Boost.space Product format
const workflow = $input.item.json.workflow;
const product = $input.item.json.product;

// Build update payload (only changed fields)
const updatePayload = {
  name: workflow.name,
  description: workflow.description || workflow.name
};

return { json: { updatePayload, workflow, productId: product.id } };

// Summarize sync results
const items = $input.all();

const summary = {
  totalProcessed: items.length,
  created: 0,
  updated: 0,
  deleted: 0,
  errors: 0,
  details: []
};

for (const item of items) {
  const data = item.json;

  // Try to determine action from response or original data
  const action = data.action || (data.id ? 'success' : 'error');

  if (action === 'CREATE' || (data.id && !data.error)) {
    summary.created++;
  } else if (action === 'UPDATE' || (data.id && !data.error)) {
    summary.updated++;
  } else if (action === 'DELETE' || (data.statusCode === 200 || data.statusCode === 204)) {
    summary.deleted++;
  }

  if (data.error || data.statusCode >= 400) {
    summary.errors++;
  }

  summary.details.push({
    action: action,
    workflowId: data.workflowId || data.sku || data.id,
    workflowName: data.workflow?.name || data.name || 'Unknown',
    success: !data.error && data.statusCode < 400,
    error: data.error || (data.statusCode >= 400 ? `HTTP ${data.statusCode}` : null)
  });
}

return { json: summary };
